import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.uOkKsJ4G.js";const u=JSON.parse('{"title":"导出格式详解","description":"Narrafiilm 支持的导出格式、参数配置与最佳实践。","frontmatter":{"title":"导出格式详解","description":"Narrafiilm 支持的导出格式、参数配置与最佳实践。"},"headers":[],"relativePath":"guide/exporting.md","filePath":"guide/exporting.md","lastUpdated":1776042696000}'),i={name:"guide/exporting.md"};function s(l,t,n,o,p,h){return d(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="导出格式详解" tabindex="-1">导出格式详解 <a class="header-anchor" href="#导出格式详解" aria-label="Permalink to &quot;导出格式详解&quot;">​</a></h1><hr><h2 id="mp4-直接输出" tabindex="-1">MP4（直接输出） <a class="header-anchor" href="#mp4-直接输出" aria-label="Permalink to &quot;MP4（直接输出）&quot;">​</a></h2><p>最常用的输出格式，兼容性最好。</p><h3 id="编码选项" tabindex="-1">编码选项 <a class="header-anchor" href="#编码选项" aria-label="Permalink to &quot;编码选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>选项</th><th>默认</th><th>说明</th></tr></thead><tbody><tr><td>编码</td><td>H.264 / H.265</td><td>H.264</td><td>H.264 兼容性最好，H.265 体积小约 40%</td></tr><tr><td>分辨率</td><td>保持原片 / 1080p / 720p / 480p</td><td>保持原片</td><td>下采样可大幅减少体积</td></tr><tr><td>帧率</td><td>保持原片 / 60 / 30 / 24</td><td>保持原片</td><td>—</td></tr><tr><td>码率</td><td>自动 / 5Mbps / 10Mbps / 20Mbps</td><td>自动</td><td>自动根据内容自适应</td></tr><tr><td>音轨</td><td>配音+原音 / 仅配音 / 仅原音</td><td>仅配音</td><td>—</td></tr></tbody></table><h3 id="推荐配置" tabindex="-1">推荐配置 <a class="header-anchor" href="#推荐配置" aria-label="Permalink to &quot;推荐配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>用途</th><th>配置</th></tr></thead><tbody><tr><td>微信 / QQ 分享</td><td>H.264 / 720p / 10Mbps</td></tr><tr><td>B站 / YouTube 上传</td><td>H.264 / 1080p / 自动码率</td></tr><tr><td>存档备份</td><td>H.265 / 保持原片 / 自动码率</td></tr><tr><td>移动端查看</td><td>H.264 / 480p / 5Mbps</td></tr></tbody></table><hr><h2 id="剪映草稿-json" tabindex="-1">剪映草稿 JSON <a class="header-anchor" href="#剪映草稿-json" aria-label="Permalink to &quot;剪映草稿 JSON&quot;">​</a></h2><p>导出原生 <code>.draft.json</code> 文件，可直接导入剪映继续精剪。</p><h3 id="导入剪映" tabindex="-1">导入剪映 <a class="header-anchor" href="#导入剪映" aria-label="Permalink to &quot;导入剪映&quot;">​</a></h3><ol><li>导出完成后，打开剪映</li><li>点击 <strong>导入</strong> → 选择导出的 <code>.draft.json</code> 文件</li><li>草稿自动加载，包含： <ul><li>时间轴和分割点</li><li>AI 配音轨道</li><li>ASS 字幕轨道（可继续编辑文字和时间）</li></ul></li></ol><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ul><li>使用最新版本剪映（较老版本可能不兼容）</li><li>草稿路径避免中文字符</li><li>剪映国际版（CapCut）部分功能不兼容中文路径草稿</li></ul><hr><h2 id="ass-字幕单独导出" tabindex="-1">ASS 字幕单独导出 <a class="header-anchor" href="#ass-字幕单独导出" aria-label="Permalink to &quot;ASS 字幕单独导出&quot;">​</a></h2><p>Narrafiilm 可以单独导出 ASS 字幕文件，不含视频：</p><ul><li><code>.ass</code> 文件：完整样式（位置/颜色/动画）</li><li><code>.srt</code> 文件：纯文本时间轴（通用格式）</li></ul><p>适用于：</p><ul><li>用 Aegisub 等专业字幕工具进一步调轴</li><li>导入 Premiere / DaVinci Resolve 继续后期</li><li>单独分享字幕文件</li></ul><hr><h2 id="输出目录" tabindex="-1">输出目录 <a class="header-anchor" href="#输出目录" aria-label="Permalink to &quot;输出目录&quot;">​</a></h2><p>默认输出到：<strong>项目目录 / output / [日期时间戳] /</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>output/</span></span>
<span class="line"><span>└── 2026-04-05_14-30-00/</span></span>
<span class="line"><span>    ├── video_final.mp4          # 成品视频</span></span>
<span class="line"><span>    ├── video_draft.json         # 剪映草稿（如选择）</span></span>
<span class="line"><span>    ├── subtitle.ass             # ASS 字幕</span></span>
<span class="line"><span>    ├── subtitle.srt             # SRT 字幕</span></span>
<span class="line"><span>    ├── narration.mp3            # 配音音频（可选）</span></span>
<span class="line"><span>    └── script.txt               # 解说稿原文</span></span></code></pre></div><hr><h2 id="导出速度参考" tabindex="-1">导出速度参考 <a class="header-anchor" href="#导出速度参考" aria-label="Permalink to &quot;导出速度参考&quot;">​</a></h2><p>以 MacBook M2（无独显）导出 5 分钟 1080p 视频为例：</p><table tabindex="0"><thead><tr><th>编码</th><th>分辨率</th><th>预计时间</th></tr></thead><tbody><tr><td>H.264</td><td>1080p</td><td>约 3–5 分钟</td></tr><tr><td>H.264</td><td>720p</td><td>约 2–3 分钟</td></tr><tr><td>H.265</td><td>1080p</td><td>约 5–8 分钟</td></tr></tbody></table>`,29)])])}const b=a(i,[["render",s]]);export{u as __pageData,b as default};
